import javax.management.*;
import javax.management.monitor.CounterMonitor;
import java.lang.management.ManagementFactory;

public class MonitorUsage {

    public static void main(String[] args) throws Exception {
        MBeanServer mbs = ManagementFactory.getPlatformMBeanServer();

        ObjectName mbeanName = new ObjectName("com.example:type=MySimpleBean");
        MySimpleBean mbean = new MySimpleBean();
        mbs.registerMBean(mbean, mbeanName);

        CounterMonitor monitor = new CounterMonitor();
        monitor.setObservedAttribute("Value");
        monitor.setGranularityPeriod(500);
        monitor.setThreshold(new Long(3));
        monitor.setNotify(true);
        monitor.setDifferenceMode(false);

        mbs.registerMBean(monitor, new ObjectName("com.example:type=MyCounterMonitor"));
        monitor.addNotificationListener((notification, handback) -> {
            System.out.println("Monitor Notification: " + notification.getMessage());
        }, null, null);

        monitor.addObservedObject(mbeanName); // Key usage of addObservedObject

        monitor.start();

        for (int i = 0; i < 5; i++) {
            Thread.sleep(1000);
            mbean.incrementValue();
            System.out.println("Bean Value: " + mbean.getValue());
        }

        monitor.stop();
        mbs.unregisterMBean(mbeanName);
        mbs.unregisterMBean(new ObjectName("com.example:type=MyCounterMonitor"));
    }
}

interface MySimpleBeanMXBean {
    int getValue();
    void incrementValue();
}

class MySimpleBean implements MySimpleBeanMXBean {
    private int value = 0;
    @Override
    public int getValue() { return value; }
    @Override
    public void incrementValue() { value++; }
}

