import javax.management.*;
import javax.management.monitor.GaugeMonitor;
import java.lang.management.ManagementFactory;

public class MonitorSetup {
    public static void main(String[] args) throws Exception {
        MBeanServer mbs = ManagementFactory.getPlatformMBeanServer();

        class MyManagedObject implements MyManagedObjectMBean {
            private int myValue = 0;
            public int getMyValue() { return myValue; }
            public void setMyValue(int myValue) { this.myValue = myValue; }
        }
        interface MyManagedObjectMBean {
            int getMyValue();
            void setMyValue(int myValue);
        }

        ObjectName observedObjectName = new ObjectName("com.example:type=MyService,id=001");
        MyManagedObject myObject = new MyManagedObject();
        mbs.registerMBean(myObject, observedObjectName);

        GaugeMonitor monitor = new GaugeMonitor();
        ObjectName monitorObjectName = new ObjectName("com.example:type=MyMonitor,name=ValueMonitor");
        mbs.registerMBean(monitor, monitorObjectName);

        monitor.setObservedAttribute("MyValue");
        monitor.setGranularityPeriod(1000L);
        monitor.setNotifyHigh(true);
        monitor.setHighThreshold(new Integer(10));

        monitor.addObservedObject(observedObjectName);

        monitor.start();
        System.out.println("Monitor started, observing " + observedObjectName);

        myObject.setMyValue(12);

        Thread.sleep(2000); 
        monitor.stop();
        mbs.unregisterMBean(monitorObjectName);
        mbs.unregisterMBean(observedObjectName);
    }
}
